function r2(n){
  if(n<0) return 0;
  let c=0;
  const s=Math.floor(Math.sqrt(n));
  for(let a=-s;a<=s;a++){
    const r=n-a*a; if(r<0) continue;
    const b=Math.round(Math.sqrt(r));
    if(b*b===r) c++;
  }
  return c;
}
function r3(n){
  if(n<0) return 0;
  let c=0;
  const s=Math.floor(Math.sqrt(n));
  for(let a=-s;a<=s;a++){
    for(let b=-s;b<=s;b++){
      const r=n-a*a-b*b; if(r<0) continue;
      const cc=Math.round(Math.sqrt(r));
      if(cc*cc===r) c+=(cc===0?1:2);
    }
  }
  return c;
}
function r4(n){
  if(n<0) return 0;
  let c=0;
  const s=Math.floor(Math.sqrt(n));
  for(let a=-s;a<=s;a++){
    for(let b=-s;b<=s;b++){
      const rem=n-a*a-b*b;
      if(rem<0) continue;
      // count reps of rem as r2
      c += r2(rem);
    }
  }
  return c;
}
