const head = document.createElement('thead');
head.innerHTML = '<tr><th>$n$</th><th>$r_2(n)$</th><th>$r_3(n)$</th><th>$r_4(n)$</th><th>smallest rep of $n$ as sum of $\\le 4$ squares</th></tr>';
t.appendChild(head);
const body = document.createElement('tbody');
function bestRep(n){
  // min k s.t. n = sum of k squares of positive ints (k up to 4)
  if(n===0) return '0';
  for(let k=1;k<=4;k++){
    const found = [];
    function go(rem, start, chosen){
      if(chosen.length===k){
        if(rem===0){ found.push([...chosen]); return true; }
        return false;
      }
      for(let x=start;x*x<=rem;x++){
        chosen.push(x);
        if(go(rem-x*x, x, chosen)) return true;
        chosen.pop();
      }
      return false;
    }
    if(go(n,1,[])) return found[0].map(x=>x+'²').join(' + ');
  }
  return '—';
}
